from PIL import Image

img = Image.open('figure.jpg')
w, h = img.size

# Detect vertical separator lines by finding columns with many white pixels
# White pixels (near 255) that span vertically might separate panels

# Sample every 10th column, find those that are mostly white
threshold = 240
for x in range(0, w, 50):
    white_count = 0
    for y in range(0, h, 10):
        r, g, b = img.getpixel((x, y))
        if r > threshold and g > threshold and b > threshold:
            white_count += 1
    ratio = white_count / (h // 10)
    if ratio > 0.8:
        print(f"Column {x}: {ratio*100:.0f}% white")

print("\nHorizontal separator lines:")
for y in range(0, h, 50):
    white_count = 0
    for x in range(0, w, 10):
        r, g, b = img.getpixel((x, y))
        if r > threshold and g > threshold and b > threshold:
            white_count += 1
    ratio = white_count / (w // 10)
    if ratio > 0.8:
        print(f"Row {y}: {ratio*100:.0f}% white")
